try {
  const raw = $input.first().json.text || $input.first().json.message?.content || $input.first().json.data || '';
  const cleaned = raw.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
  const parsed = JSON.parse(cleaned);

  const row = {
    original_text: $('Telegram Trigger').item.json.message.text,
    summary: parsed.summary || 'Без описания',
    tags: parsed.tags || [],
    life_area: parsed.life_area || 'работа',
    theme: parsed.theme || '',
    signal_type: parsed.signal_type || 'news',
    relevance_score: parsed.relevance_score || 0,
    route: parsed.route || 'pending',
    routed_to_project: parsed.routed_to_project || null,
    next_step: parsed.next_step || '',
    original_date: new Date($('Telegram Trigger').item.json.message.date * 1000).toISOString(),
    source_id: null // пока без авто-матчинга источников для простоты
  };
  return { json: row };
} catch (err) {
  throw new Error('LLM did not return valid JSON: ' + err.message + '. Raw response: ' + $input.first().json.text);
}
